    "about_title": "Chi siamo",
    "about_text": "Sviluppato da Liam Anstey nel Regno Unito. Queste app sono strumenti di supporto al benessere progettati per integrare la riabilitazione professionale — non sono dispositivi medici. Segui sempre le indicazioni del tuo clinico.",
    "contact_title": "Contatti",
    "footer_copy": "© 2026 Anstey Apps",
    "footer_privacy": "Privacy:",
    "ss_page_subtitle": "Allenatore del Campo Visivo",
    "ss_back": "Torna alla home",
    "ss_exercises_title": "Quattro esercizi per il recupero del campo visivo",
    "ss_exercises_intro": "Stroke Sight offre un allenamento strutturato del campo visivo progettato per incoraggiare i movimenti oculari verso il lato colpito. Ogni esercizio si concentra su un aspetto diverso della riabilitazione visiva.",
    "ss_ex1_name": "Ricerca Saccadica",
    "ss_ex1_desc": "Individua e tocca i bersagli che appaiono nel tuo campo visivo, allenando movimenti oculari rapidi verso il lato colpito.",
    "ss_ex2_name": "Esplorazione Visiva",
    "ss_ex2_desc": "Esplora sistematicamente un campo di elementi per localizzare bersagli specifici, sviluppando schemi di esplorazione costanti.",
    "ss_ex3_name": "Allenatore di Lettura",
    "ss_ex3_desc": "Esercitati a seguire righe di testo con bersagli evidenziati, per supportare il ritorno alla lettura.",
    "ss_ex4_name": "Esplorazione Libera",
    "ss_ex4_desc": "Esercizi di ricerca visiva aperti che si adattano al tuo ritmo e ai tuoi progressi.",
    "ss_features_title": "Caratteristiche principali",
    "ss_feat_langs": "17 lingue",
    "ss_feat_langs_desc": "Inglese, spagnolo, francese, tedesco, italiano, portoghese, gallese, giapponese, coreano, hindi, arabo, cinese, polacco, spagnolo latinoamericano, portoghese brasiliano e francese canadese",
    "ss_feat_levels": "10 livelli di difficoltà progressivi",
    "ss_feat_levels_desc": "Inizia con calma e aumenta la sfida man mano che migliori",
    "ss_feat_sides": "Supporto per lato sinistro e destro",
