    "rw_faq_a1": "नहीं। ReWrite एक वेलनेस सपोर्ट टूल है जो पेशेवर पुनर्वास को पूरक बनाने के लिए डिज़ाइन किया गया है। यह किसी भी स्थिति का निदान, उपचार या इलाज नहीं करता। इसे हमेशा अपने व्यावसायिक चिकित्सक या देखभाल टीम के मार्गदर्शन के साथ उपयोग करें।",
    "rw_faq_q2": "वर्ण ट्रेसिंग के लिए यह कौन सी भाषाओं का समर्थन करता है?",
    "rw_faq_a2": "सही स्ट्रोक क्रम के साथ पूर्ण चीनी और जापानी वर्ण समर्थन सहित सभी 17 भाषाएँ। अरबी को दाएँ से बाएँ लेआउट के साथ समर्थित किया गया है। प्रत्येक भाषा में अपनी शब्द और वाक्य सामग्री है — केवल अनुवादित इंटरफेस नहीं।",
    "rw_faq_q3": "क्या मैं अपनी प्रगति अपने चिकित्सक के साथ साझा कर सकता/सकती हूँ?",
    "rw_faq_a3": "हाँ — ReWrite में एक ईमेल प्रगति रिपोर्ट सुविधा है जो एक सारांश तैयार करती है जिसे आप अपने डिवाइस के मेल ऐप के माध्यम से भेजते हैं। हमारे द्वारा कोई डेटा संग्रहीत या प्रसंस्कृत नहीं किया जाता।",
    "rw_faq_q4": "क्या कोई सब्सक्रिप्शन है?",
    "rw_faq_a4": "नहीं। £29.99 एकमुश्त खरीद। कोई सब्सक्रिप्शन नहीं, कोई इन-ऐप खरीदारी नहीं, कोई विज्ञापन नहीं।",
    "rw_faq_q5": "क्या यह ऑफलाइन काम करता है?",
    "rw_faq_a5": "हाँ। पहले डाउनलोड के बाद, सब कुछ इंटरनेट कनेक्शन के बिना काम करता है।",
    "rw_faq_q6": "क्या मैं इसे टैबलेट पर उपयोग कर सकता/सकती हूँ?",
    "rw_faq_a6": "हाँ। ReWrite फोन और टैबलेट दोनों पर काम करता है। बड़ी स्क्रीन ट्रेसिंग को आसान बना सकती है और यदि आपके पास टैबलेट है तो इसे आज़माना उचित है।",
    "rw_cta_sub": "अक्षर ट्रेसिंग अभ्यास मुफ्त में आज़माएं — कोई अकाउंट नहीं चाहिए",
    "rw_testimonials_title": "लोग क्या कह रहे हैं",
    "rw_testimonials_placeholder": "समीक्षाएँ और क्लिनिकल फीडबैक आते ही यहाँ दिखाई देंगे। यदि आपने ReWrite का उपयोग किया है और अपना अनुभव साझा करना चाहते हैं, तो कृपया <a href=\"mailto:liam@ansteyapps.com\" style=\"color:var(--color-primary)\">संपर्क करें</a>।",
    "about_attribution": "Liam Anstey, संस्थापक",
    "contact_intro": "चाहे आप ऐप्स की सिफारिश करने पर विचार कर रहे क्लिनिशियन हों, संस्थागत लाइसेंसिंग तलाश रहे कमिश्नर हों, स्ट्रोक रिकवरी पर लिख रहे पत्रकार हों, या प्रश्न वाले स्ट्रोक सर्वाइवर हों — मैं वास्तव में आपसे सुनना चाहूँगा।",
    "hero_subtitle": "पेशेवर देखभाल के साथ-साथ प्रतिदिन 10 से 20 मिनट के अभ्यास को समर्थन देने के लिए साक्ष्य-आधारित ऐप्स।",
    "cond_hemianopia": "अर्धदृष्टिता",
    "cond_hemianopia_desc": "दृश्य क्षेत्र के आधे हिस्से का नुकसान, आमतौर पर दृश्य मार्गों को प्रभावित करने वाले स्ट्रोक के बाद।",
    "cond_quadrantanopia": "चतुर्थांश दृष्टिहीनता",
    "cond_quadrantanopia_desc": "दृश्य क्षेत्र के एक चतुर्थांश का नुकसान; अर्धदृष्टिता का आंशिक रूप।",
    "cond_neglect": "एकपक्षीय स्थानिक उपेक्षा",
